from llama_index.core import VectorStoreIndex, SimpleDirectoryReader
import spacy
nlp = spacy.load('en_core_web_sm')

index = VectorStoreIndex.from_documents(SimpleDirectoryReader('data/').load_data())

queries = ["leadership qualities", "technical skills"]
entity_counts = {'MALE': 0, 'FEMALE': 0}

for query in queries:
    response = index.as_query_engine().query(query)
    doc = nlp(response.response)
    for ent in doc.ents:
        if ent.label_ == 'PERSON':
            if any(male in ent.text.lower() for male in ['john', 'mike', 'david']):
                entity_counts['MALE'] += 1
            elif any(female in ent.text.lower() for female in ['sarah', 'emily', 'lisa']):
                entity_counts['FEMALE'] += 1

parity = abs(entity_counts['MALE'] - entity_counts['FEMALE']) / sum(entity_counts.values())
print(f"Demographic parity violation: {parity:.3f}")
